  ('social-worker-moex-01791', 'social-worker', 'social-worker-moex-107-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '佛洛伊德（Freud）的心理分析理論指出人格有三個部分，分別是：', '["本我、自我、原慾（libido）", "潛意識、意識、超我", "自我、超我、次自我", "超我、自我、本我"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "0f97a01c1698", "answer_pdf_sha1": "501bbd54e4d6", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01792', 'social-worker', 'social-worker-moex-107-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '艾瑞克森（Erikson）的人格發展理論主要強調：', '["反覆解決性驅力的潛在衝突", "不同生命週期的發展任務", "兒童思想隨著成熟而改變", "各階段身體發展受敏感期的影響"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "0f97a01c1698", "answer_pdf_sha1": "501bbd54e4d6", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01793', 'social-worker', 'social-worker-moex-107-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '有關生命歷程觀點，下列何項敘述正確？', '["生命歷程觀點的主要概念，包括世代、過渡期、軌跡、生命事件、轉捩點", "生命歷程觀點是涵蓋巨視的社會文化結構面與微視的家庭系統", "「過渡期」是指人一生中扮演和轉換不同的角色與身分的時期", "「世代」是指不同年齡層在不同時空背景下，具有共同興趣的一群人"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "0f97a01c1698", "answer_pdf_sha1": "501bbd54e4d6", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01794', 'social-worker', 'social-worker-moex-107-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '請問下列那項症狀較不是受到生理因素影響？', '["亞斯伯格症", "發展遲緩", "自閉症", "嬰兒搖晃症候群"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "0f97a01c1698", "answer_pdf_sha1": "501bbd54e4d6", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01795', 'social-worker', 'social-worker-moex-107-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '正常的新生嬰兒都會出現反射動作，例如當輕觸嬰兒的嘴唇或嘴唇旁的臉頰時，便自發性轉動頭部並且 開始吸吮，請問下列那一個概念最符合前述的反射特徵？', '["吸吮反射", "尋乳反射", "巴氏反射", "驚嚇反射"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "0f97a01c1698", "answer_pdf_sha1": "501bbd54e4d6", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01796', 'social-worker', 'social-worker-moex-107-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '下列有關皮亞傑（Piaget）的認知發展理論，下列何者是屬於「運思前期」階段的認知發展特徵？①不可', '["自我中心主義", "專注焦點集中在某一細節上而忽略其他", "物體質量保留觀念", ""]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "0f97a01c1698", "answer_pdf_sha1": "501bbd54e4d6", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 30, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01797', 'social-worker', 'social-worker-moex-107-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '兒童虐待對兒童造成的影響可能包括那些？①易怒  ②低自尊  ③自傷傷人', '["", "", "", ""]'::jsonb, 3, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "0f97a01c1698", "answer_pdf_sha1": "501bbd54e4d6", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 31, "answer_corrected": false, "flags": ["incomplete_options"], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01798', 'social-worker', 'social-worker-moex-107-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '依據佛洛依德（Freud）的觀點，在性蕾期（phallic stage）的階段，男孩產生因愛上母親但又害怕被父親 發現自己的內心衝突，此時男孩擔心父親的報復而必須透過防衛機轉來解決心中對母親強烈的依戀，以 保護自己，關於男孩內心的衝突情緒，屬下列何者的概念？', '["戀母情結（Oedipus complex）", "閹割焦慮（Castration anxiety）", "固著現象（Fixation）", "戀父情結（Electra complex）"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "0f97a01c1698", "answer_pdf_sha1": "501bbd54e4d6", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 32, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01799', 'social-worker', 'social-worker-moex-107-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '防衛機轉（defense mechanisms）是用以對抗日常生活中所引發的焦慮。當一個人把衝動轉移到另一個對 象而非原來可以滿足自己的對象身上，例如：怨恨老師的學生，想表達自己的敵意但又怕受到懲罰，可 能會轉移攻擊性到其他事物上，像是透過電玩或是寵物出氣，請問這是運用下列那一種防衛機轉？', '["否定（denial）", "反向（reaction formation）", "替代（displacement）", "昇華（sublimation）"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "0f97a01c1698", "answer_pdf_sha1": "501bbd54e4d6", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 33, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL),
  ('social-worker-moex-01800', 'social-worker', 'social-worker-moex-107-0e79f916', 'sub-social-worker-01', NULL, 'single_choice', '關於老年人常見的疾病，認知缺陷的風險隨著年齡增加，且不可逆轉地影響其記憶、人格或功能，下列 敘述何者正確？', '["失智症（dementia）是阿茲海默症（Alzheimer’s disease）的一種類型", "阿茲海默症（Alzheimer’s disease）是失智症（dementia）的一種類型", "阿茲海默症（Alzheimer’s disease）與失智症（dementia）是無關", "帕金森氏症（Parkinson’s disease）是失智症（dementia）的一種類型"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:30:10+00:00", "source_pdf_sha1": "0f97a01c1698", "answer_pdf_sha1": "501bbd54e4d6", "source_family": "moex-gov-tw", "moex": {"exam_code": "107030", "c": "107", "s": "0605", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "人類行為與社會環境", "year": "107", "exam_name": "107年第一次專技人員高等考試中醫師考試分階段考試、營養師、心理師、護理師、社會工作師考試", "original_question_number": 34, "answer_corrected": false, "flags": [], "slug": "socialworker", "db_exam_id": "social-worker"}'::jsonb, NULL)
